    const acceptedSantri = await db.select({ count: sql`count(*)` }).from(santri).where(eq(santri.status, "accepted")).then((res) => res[0].count);
    const totalUsers = await db.select({ count: sql`count(*)` }).from(users).then((res) => res[0].count);
    const maleCount = await db.select({ count: sql`count(*)` }).from(santri).where(eq(santri.jenisKelamin, "L")).then((res) => res[0].count);
    const femaleCount = await db.select({ count: sql`count(*)` }).from(santri).where(eq(santri.jenisKelamin, "P")).then((res) => res[0].count);
    const genderDistribution = [
      { name: "Laki-laki", value: Number(maleCount), fill: "#0ea5e9" },
      { name: "Perempuan", value: Number(femaleCount), fill: "#ec4899" }
    ];
    const allSantriDates = await db.select({ date: santri.createdAt }).from(santri);
    const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
    const currentMonth = (/* @__PURE__ */ new Date()).getMonth();
    const stats = [];
