core.post("/programs", adminMiddleware, zValidator("json", createProgramSchema), async (c2) => {
  const data = c2.req.valid("json");
  let slug = data.slug;
  if (!slug || slug.trim() === "") {
    slug = data.nama.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)+/g, "");
    if (!slug) {
      slug = `program-${Date.now()}`;
    }
  }
  const existing = await db.select().from(programs).where(eq(programs.slug, slug));
  if (existing.length > 0) {
    slug = `${slug}-${Date.now()}`;
  }
  const [item] = await db.insert(programs).values({
    ...data,
    slug,
    status: data.status || "published",
    isFeatured: data.isFeatured ?? false,
    metaTitle: data.metaTitle || data.nama,
    metaDescription: data.metaDescription || data.deskripsi.substring(0, 150),
    order: data.order ?? 0,
    createdAt: (/* @__PURE__ */ new Date()).toISOString(),
    updatedAt: (/* @__PURE__ */ new Date()).toISOString()
  }).returning();
  return c2.json(item);
});
core.put("/programs/:id", adminMiddleware, zValidator("json", updateProgramSchema), async (c2) => {
  const id = parseInt(c2.req.param("id"));
  const data = c2.req.valid("json");
  const formattedData = {
    ...data,
    tanggalMulai: data.tanggalMulai ? new Date(data.tanggalMulai) : void 0,
    tanggalSelesai: data.tanggalSelesai ? new Date(data.tanggalSelesai) : void 0,
    updatedAt: (/* @__PURE__ */ new Date()).toISOString()
  };
  await db.update(programs).set(formattedData).where(eq(programs.id, id));
  const [item] = await db.select().from(programs).where(eq(programs.id, id));
  return c2.json(item);
});
