media2.post("/upload", authMiddleware, async (c2) => {
  try {
    const body = await c2.req.parseBody();
    const file = body["file"];
    console.log("Upload Request Body Keys:", Object.keys(body));
    if (file instanceof File) {
      console.log("File details:", {
        name: file.name,
        type: file.type,
        size: file.size
      });
    } else {
      console.error("File is not a File instance:", file);
    }
    if (!file || !(file instanceof File)) {
      return c2.json({ error: "No file uploaded or invalid format" }, 400);
    }
    const buffer = await file.arrayBuffer();
    const fileBuffer = Buffer.from(buffer);
    const metadata = {
      filename: file.name,
      mimetype: file.type,
      size: file.size
    };
    const options = {
      category: body["category"] || "general",
      folder: body["folder"] || "/",
      tags: body["tags"] || "",
      userId: c2.get("user").id,
      provider: body["provider"] || void 0
    };
    const result = await mediaService.processUpload(fileBuffer, metadata, options);
    return c2.json(result, 201);
  } catch (error) {
    console.error("Upload endpoint error:", error);
    return c2.json({
      error: "Failed to upload file",
      details: error instanceof Error ? error.message : String(error)
    }, 500);
  }
});
