var app2 = new Hono2();
app2.use("*", logger());
app2.use("*", cors({
  origin: process.env.FRONTEND_URL || "*",
  credentials: true
}));
app2.use("*", prettyJSON());
app2.onError((err, c2) => {
  console.error("[API ERROR]:", err);
  const isDbError = err?.name === "NeonDbError" || err?.message?.toLowerCase().includes("database") || err?.code?.startsWith("57");
  if (isDbError) {
    console.error("CRITICAL: Database connection issue detected.");
  }
  return c2.json({
    error: err?.message || "Internal Server Error",
    message: err?.code ? `Code: ${err.code}` : void 0,
    name: err?.name,
    stack: process.env.NODE_ENV !== "production" ? err?.stack : void 0,
    path: c2.req.path,
    timestamp: (/* @__PURE__ */ new Date()).toISOString()
  }, 500);
});
app2.get("/", (c2) => {
  return c2.json({
    message: "Pesantren Hub API is running",
    version: "1.0.0",
    timestamp: (/* @__PURE__ */ new Date()).toISOString(),
    environment: process.env.NODE_ENV || "development"
  });
});
app2.get("/health", (c2) => {
  return c2.json({ status: "ok", uptime: process.uptime() });
});
